<body>
    <div class="container">
        <h1>🍅 番茄钟</h1>
        <p class="session-type" id="sessionType">专注时间</p>

        <div class="mode-toggle">
            <button class="mode-btn active" data-mode="work" onclick="setMode('work')">专注</button>
            <button class="mode-btn" data-mode="shortBreak" onclick="setMode('shortBreak')">短休息</button>
            <button class="mode-btn" data-mode="longBreak" onclick="setMode('longBreak')">长休息</button>
        </div>

        <div class="timer">
            <svg class="timer-ring" width="220" height="220">
                <circle class="bg" cx="110" cy="110" r="100"></circle>
                <circle class="progress" id="progress" cx="110" cy="110" r="100" 
                        stroke-dasharray="628.3" stroke-dashoffset="0"></circle>
            </svg>
            <div class="time-display" id="timeDisplay">25:00</div>
        </div>

        <div class="controls">
            <button class="btn-primary" id="startBtn" onclick="toggleTimer()">开始</button>
            <button class="btn-secondary" onclick="resetTimer()">重置</button>
        </div>

        <div class="settings">
            <div class="setting-item">
                <label>专注 (分钟)</label>
                <input type="number" id="workTime" value="25" min="1" max="120" onchange="updateSettings()">
            </div>
            <div class="setting-item">
                <label>短休息 (分钟)</label>
                <input type="number" id="shortBreakTime" value="5" min="1" max="30" onchange="updateSettings()">
            </div>
            <div class="setting-item">
                <label>长休息 (分钟)</label>
                <input type="number" id="longBreakTime" value="15" min="1" max="60" onchange="updateSettings()">
            </div>
        </div>

        <div class="stats">
            <div class="stat">
                <div class="stat-value" id="pomodoroCount">0</div>
                <div class="stat-label">已完成</div>
            </div>
            <div class="stat">
                <div class="stat-value" id="totalTime">0</div>
                <div class="stat-label">总分钟</div>
            </div>
        </div>
    </div>

    <div class="notification" id="notification"></div>

    <script>
        // Timer state
        let timer = null;
        let timeLeft = 25 * 60;
        let totalTime = 25 * 60;
        let isRunning = false;
        let currentMode = 'work';
        let pomodoroCount = 0;
        let totalFocusTime = 0;

        // Settings
        let settings = {
            work: 25,
            shortBreak: 5,
            longBreak: 15
        };

        // Audio context for notifications
        let audioContext = null;

        function initAudio() {
            if (!audioContext) {
                audioContext = new (window.AudioContext || window.webkitAudioContext)();
            }
        }

        function playSound(frequency, duration, type = 'sine') {
            if (!audioContext) return;

            const oscillator = audioContext.createOscillator();
            const gainNode = audioContext.createGain();

            oscillator.connect(gainNode);
            gainNode.connect(audioContext.destination);

            oscillator.frequency.value = frequency;
            oscillator.type = type;

            gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
            gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + duration);

            oscillator.start(audioContext.currentTime);
            oscillator.stop(audioContext.currentTime + duration);
        }

        function playNotification() {
            initAudio();
            playSound(523.25, 0.2);
            setTimeout(() => playSound(659.25, 0.2), 200);
            setTimeout(() => playSound(783.99, 0.3), 400);
        }

        function updateDisplay() {
            const minutes = Math.floor(timeLeft / 60);
            const seconds = timeLeft % 60;
            document.getElementById('timeDisplay').textContent = 
                `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;

            // Update progress ring
            const circumference = 2 * Math.PI * 100;
            const progress = (totalTime - timeLeft) / totalTime;
            const offset = circumference * (1 - progress);
            document.getElementById('progress').style.strokeDashoffset = offset;

            // Update page title
            document.title = `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')} - 番茄钟`;
        }

        function toggleTimer() {
            if (isRunning) {
                pauseTimer();
            } else {
                startTimer();
            }
        }

        function startTimer() {
            initAudio();
            isRunning = true;
            document.getElementById('startBtn').textContent = '暂停';

            timer = setInterval(() => {
                if (timeLeft > 0) {
                    timeLeft--;
                    if (currentMode === 'work') {
                        totalFocusTime++;
                    }
                    updateDisplay();
                } else {
                    completeSession();
                }
            }, 1000);
        }

        function pauseTimer() {
            isRunning = false;
            document.getElementById('startBtn').textContent = '继续';
            clearInterval(timer);
        }

        function resetTimer() {
            clearInterval(timer);
            isRunning = false;
            document.getElementById('startBtn').textContent = '开始';

            const times = {
                work: settings.work,
                shortBreak: settings.shortBreak,
                longBreak: settings.longBreak
            };

            timeLeft = times[currentMode] * 60;
            totalTime = timeLeft;
            updateDisplay();
        }

        function completeSession() {
            clearInterval(timer);
            isRunning = false;
            playNotification();

            if (currentMode === 'work') {
                pomodoroCount++;
                document.getElementById('pomodoroCount').textContent = pomodoroCount;
                document.getElementById('totalTime').textContent = Math.floor(totalFocusTime / 60);
                showNotification('🍅 专注完成！休息一下吧');

                // Auto switch to break
                if (pomodoroCount % 4 === 0) {
                    setMode('longBreak');
                } else {
                    setMode('shortBreak');
                }
            } else {
                showNotification('⚡ 休息结束！开始新的专注');
                setMode('work');
            }
        }

        function setMode(mode) {
            currentMode = mode;
            document.querySelectorAll('.mode-btn').forEach(btn => {
                btn.classList.toggle('active', btn.dataset.mode === mode);
            });

            const modeNames = {
                work: '专注时间',
                shortBreak: '短休息',
                longBreak: '长休息'
            };
            document.getElementById('sessionType').textContent = modeNames[mode];

            const progress = document.getElementById('progress');
            progress.classList.toggle('break', mode !== 'work');

            resetTimer();
        }

        function updateSettings() {
            settings.work = parseInt(document.getElementById('workTime').value) || 25;
            settings.shortBreak = parseInt(document.getElementById('shortBreakTime').value) || 5;
            settings.longBreak = parseInt(document.getElementById('longBreakTime').value) || 15;

            if (!isRunning) {
                resetTimer();
            }
        }

        function showNotification(message) {
            const notification = document.getElementById('notification');
            notification.textContent = message;
            notification.classList.add('show');

            setTimeout(() => {
                notification.classList.remove('show');
            }, 3000);
        }

        // Request notification permission
        if ('Notification' in window && Notification.permission === 'default') {
            Notification.requestPermission();
        }

        // Initialize
        updateDisplay();
    </script>
</body>
</html>"}
